def get_blokus_pieces(n):
    pieces = []
    def get_pieces(size, piece, x, y):
        if len(piece) == size:
            piece = normalize(piece)
            if piece not in pieces:
                pieces.append(piece)
            return
        for dx, dy in [(0, 1), (0, -1), (1, 0), (-1, 0)]:
            nx, ny = x + dx, y + dy
            if (nx, ny) not in piece:
                piece.add((nx, ny))
                get_pieces(size, piece, nx, ny)
                piece.remove((nx, ny))
    def normalize(piece):
        minx = min(x for x, y in piece)
        miny = min(y for x, y in piece)
        piece = {(x - minx, y - miny) for x, y in piece}
        rotations = []
        for _ in range(4):
            rotations.append(tuple(sorted([(y, -x) for x, y in piece])))
            piece = {(y, -x) for x, y in piece}
        flips = []
        for rotation in rotations:
            flips.append(tuple(sorted([(-x, y) for x, y in rotation])))
        return min(rotations + flips)
    get_pieces(n, {(0, 0)}, 0, 0)
    return pieces

