def find_polyominoes(n):
    def rotate(p):
        return [tuple(-y, x) for x, y in p]

    def reflect(p):
        return [tuple(-x, y) for x, y in p]

    def normalize(p):
        min_x = min(x for x, y in p)
        min_y = min(y for x, y in p)
        return tuple(sorted((x - min_x, y - min_y) for x, y in p))

    def generate_polys(n, p=[]):
        if len(p) == n:
            yield normalize(p)
        else:
            for dx, dy in [(1, 0), (-1, 0), (0, 1), (0, -1)]:
                x, y = p[-1] if p else (0, 0)
                new_p = p + [(x + dx, y + dy)]
                if all(0 <= x + dx <= n and 0 <= y + dy <= n for x, y in new_p) and all(abs(x1 - x2) + abs(y1 - y2) == 1 for (x1, y1), (x2, y2) in zip(new_p, new_p[1:])) and new_p[-1] not in p:
                    yield from generate_polys(n, new_p)

    polys = set(generate_polys(n))
    unique_polys = set()
    for p in polys:
        rotations = {normalize(rotate(p)), normalize(rotate(rotate(p))), normalize(rotate(rotate(rotate(p)))), normalize(rotate(rotate(rotate(rotate(p)))))}
        reflections = {normalize(reflect(p)), normalize(reflect(rotate(p))), normalize(reflect(rotate(rotate(p)))), normalize(reflect(rotate(rotate(rotate(p)))))}
        all_variations = rotations | reflections
        if p == min(all_variations):
            unique_polys.add(p)

    return len(unique_polys), unique_polys

