def find_polyominoes(n):
    def rotate(polyomino):
        return [(y, -x) for x, y in polyomino]

    def reflect(polyomino):
        return [(-x, y) for x, y in polyomino]

    def normalize(polyomino):
        min_x = min(x for x, y in polyomino)
        min_y = min(y for x, y in polyomino)
        polyomino = [(x - min_x, y - min_y) for x, y in polyomino]
        rotations = [polyomino]
        for _ in range(3):
            polyomino = rotate(polyomino)
            rotations.append(polyomino)
        reflections = [reflect(r) for r in rotations]
        rotations.extend(reflections)
        return min(rotations, key=lambda p: (p[0], tuple(sorted(p))))

    def find_polyominoes_recursive(n, current_polyomino, current_position):
        if len(current_polyomino) == n:
            yield normalize(current_polyomino)
        else:
            for dx, dy in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
                new_position = (current_position[0] + dx, current_position[1] + dy)
                if new_position not in current_polyomino:
                    yield from find_polyominoes_recursive(n, current_polyomino + [new_position], new_position)

