def get_polyominoes(n):
    polyominoes = set()
    for p in itertools.product(range(2), repeat=n):
        if sum(p) == 0:
            continue
        polyomino = []
        for i in range(n):
            if p[i] == 1:
                polyomino.append(i)
        polyominoes.add(tuple(sorted(polyomino)))
    return polyominoes

def get_polyominoes_with_symmetry(n):
    polyominoes = set()
    for p in itertools.product(range(2), repeat=n):
        if sum(p) == 0:
            continue
        polyomino = []
        for i in range(n):
            if p[i] == 1:
                polyomino.append(i)
        symmetries = set()
        symmetries.add(tuple(sorted(polyomino)))
        symmetries.add(tuple(sorted([n-1-i for i in polyomino])))
        symmetries.add(tuple(sorted([n-1-i for i in reversed(polyomino)])))
        symmetries.add(tuple(sorted(reversed(polyomino))))
        polyominoes.add(min(symmetries))
    return polyominoes

