        polyomino = []
        for i in range(n):
            if p[i] == 1:
                polyomino.append(i)
        rotations = set()
        rotations.add(tuple(sorted(polyomino)))
        rotations.add(tuple(sorted([n-1-i for i in polyomino])))
        rotations.add(tuple(sorted([n-1-i for i in reversed(polyomino)])))
        rotations.add(tuple(sorted(reversed(polyomino))))
        symmetries = set()
