import itertools

def get_polyominoes(n):
    # Generate all possible polyominoes of size n
    polyominoes = set()
    for p in itertools.product([0, 1], repeat=n*4):
        grid = [list(p[i:i+4]) for i in range(0, n*4, 4)]
        if sum(sum(row) for row in grid) == n:
            # Check if the polyomino is connected
            if is_connected(grid):
                # Normalize the polyomino
                normalized = normalize(grid)
                polyominoes.add(tuple(map(tuple, normalized)))
    return polyominoes

def is_connected(grid):
    # Check if the polyomino is connected using DFS
    rows, cols = len(grid), len(grid[0])
    visited = [[False]*cols for _ in range(rows)]
    stack = [(0, 0)]
    while stack:
        r, c = stack.pop()
        if visited[r][c]:
            continue
        visited[r][c] = True
        for dr, dc in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            nr, nc = r + dr, c + dc
            if 0 <= nr < rows and 0 <= nc < cols and grid[nr][nc] == 1 and not visited[nr][nc]:
                stack.append((nr, nc))
    return all(all(cell == 1 or visited[r][c] for c, cell in enumerate(row)) for r, row in enumerate(grid))

def normalize(grid):
    # Normalize the polyomino by rotating and flipping
    rows, cols = len(grid), len(grid[0])
    min_r, max_r, min_c, max_c = rows, -1, cols, -1
    for r, row in enumerate(grid):
        for c, cell in enumerate(row):
            if cell == 1:
                min_r, max_r = min(min_r, r), max(max_r, r)
                min_c, max_c = min(min_c, c), max(max_c, c)
    grid = [row[min_c:max_c+1] for row in grid[min_r:max_r+1]]
    rotations = []
    for _ in range(4):
        grid = list(zip(*grid[::-1]))
        rotations.append(grid)
    normalized = min(rotations, key=lambda x: (len(x), len(x[0]), x))
    return normalized

