def find_blokus_pieces(n):
    pieces = []
    for i in range(1, n+1):
        for j in range(1, n+1):
            if i * j > n:
                break
            if i * j == n:
                pieces.append((i, j))
    unique_pieces = set()
    for piece in pieces:
        rotations = [(piece[0], piece[1]), (piece[1], piece[0]), (piece[0], -piece[1]), (-piece[0], piece[1])]
        for rotation in rotations:
            if rotation[0] <= rotation[1]:
                unique_pieces.add(rotation)
    return len(unique_pieces), unique_pieces

