        reflections.add(tuple(sorted({(-x, y) for x, y in piece})))
        return reflections

    def get_symmetries(piece):
        symmetries = set()
        for rotation in get_rotations(piece):
            symmetries.add(rotation)
            symmetries.add(tuple(sorted({-x for x, y in rotation}), sorted({y for x, y in rotation})))
        return symmetries

