        if piece is None:
            piece = [[0]*size for _ in range(size)]
        for i in range(size):
            for j in range(size):
                if piece[i][j] == 0:
                    piece[i][j] = 1
                    yield from generate_possibilities(size, piece, x, y)
                    piece[i][j] = 0
        add_piece(piece, x, y)

