            for j in range(len(piece[0])):
                if piece[i][j] == 1:
                    row.append(1)
                else:
                    row.append(0)
            normalized_piece.append(row)
        return tuple(tuple(row) for row in normalized_piece)

    def generate_rotations(piece):
        yield normalize_piece(piece)
        for _ in range(3):
            piece = [list(reversed(x)) for x in zip(*piece)]
            yield normalize_piece(piece)

    def generate_flips(piece):
        yield from generate_rotations(piece)
        piece = piece[::-1]
        yield from generate_rotations(piece)

    def generate_n_square_possibilities(n):
        for size in range(1, n+1):
            yield from generate_possibilities(size)
        possibilities_to_return = set()
        for piece in list(possibilities):
            if len(piece) == n:
                for rotation in generate_flips([[1]*(y+1) for y in range(piece[1]-piece[0])]):
                    if sum(len(row) for row in rotation) == n:
                        possibilities_to_return.add(rotation)
        return possibilities_to_return

    return generate_n_square_possibilities(n)

