import itertools

def generate_polyominoes(n):
    polyominoes = []
    for r in range(1, n + 1):
        for combo in itertools.combinations(range(n * n), r):
            grid = [[0] * n for _ in range(n)]
            for x in combo:
                grid[x // n][x % n] = 1
            if is_connected(grid):
                polyominoes.append(grid)
    return polyominoes

def is_connected(grid):
    n = len(grid)
    visited = [[False] * n for _ in range(n)]
    for i in range(n):
        for j in range(n):
            if grid[i][j] == 1 and not visited[i][j]:
                if not dfs(grid, visited, i, j):
                    return False
    return True

def dfs(grid, visited, i, j):
    n = len(grid)
    if i < 0 or i >= n or j < 0 or j >= n or grid[i][j] == 0 or visited[i][j]:
        return True
    visited[i][j] = True
    directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]
    for d in directions:
        if not dfs(grid, visited, i + d[0], j + d[1]):
            return False
    return True

